/**
 * UTS (uni type script) 类型声明文件
 * 文档: https://doc.dcloud.net.cn/uni-app-x/uts/data-type.html
 */

// ==================== UTS 内置类型 ====================

/**
 * UTS JSON 对象类型
 * 用于表示 JSON 数据结构
 */
declare class UTSJSONObject {
    /**
     * 构造函数
     */
    constructor()
    constructor(object: Record<string, any>)
    
    /**
     * 通过 keyPath 获取字符串值
     */
    getString(keyPath: string): string | null
    
    /**
     * 通过 keyPath 获取数字值
     */
    getNumber(keyPath: string): number | null
    
    /**
     * 通过 keyPath 获取布尔值
     */
    getBoolean(keyPath: string): boolean | null
    
    /**
     * 通过 keyPath 获取 JSON 对象
     */
    getJSON(keyPath: string): UTSJSONObject | null
    
    /**
     * 通过 keyPath 获取数组
     */
    getArray(keyPath: string): UTSJSONObject[] | null
    
    /**
     * 通过 keyPath 获取任意类型值
     */
    getAny(keyPath: string): any
    
    /**
     * 设置键值对
     */
    set(key: string, value: any): void
    
    /**
     * 转换为 Map
     */
    toMap(): Map<string, any>
    
    /**
     * 通过下标访问属性
     */
    [key: string]: any
}

/**
 * UTS 数组类型
 * 继承自 ArrayList，支持变长操作
 */
declare class UTSArray<T> extends Array<T> {
    /**
     * 从原生数组转换
     */
    static fromNative<T>(nativeArray: any): UTSArray<T>
    
    /**
     * 转换为 Kotlin List
     */
    toKotlinList(): any
    
    /**
     * 转换为 TypedArray
     */
    toTypedArray(): any
}

/**
 * UTS Map 类型
 */
declare class UTSMap<K, V> extends Map<K, V> {
}

/**
 * UTS Set 类型
 */
declare class UTSSet<T> extends Set<T> {
}

// ==================== 平台专有数字类型 ====================

/** 8位整数 */
declare type Int8 = number
/** 16位整数 */
declare type Int16 = number
/** 32位整数 */
declare type Int32 = number
/** 64位整数 */
declare type Int64 = number
/** 整数类型 */
declare type Int = number

/** 8位无符号整数 */
declare type UInt8 = number
/** 16位无符号整数 */
declare type UInt16 = number
/** 32位无符号整数 */
declare type UInt32 = number
/** 64位无符号整数 */
declare type UInt64 = number
/** 无符号整数类型 */
declare type UInt = number

/** 单精度浮点数 */
declare type Float = number
/** 双精度浮点数 */
declare type Double = number

/** 字节类型 */
declare type Byte = number

// ==================== Number 扩展方法 ====================

interface Number {
    /** 转换为 Int */
    toInt(): Int
    /** 转换为 Float */
    toFloat(): Float
    /** 转换为 Double */
    toDouble(): Double
    /** 转换为 Long */
    toLong(): Int64
    /** 转换为 Byte */
    toByte(): Byte
}

declare const Number: {
    /** 从原生类型创建 number */
    from(value: any): number
    /** 从原生类型创建 number */
    from(value: Int): number
    /** 从原生类型创建 number */
    from(value: Float): number
    /** 从原生类型创建 number */
    from(value: Double): number
    /** 从原生类型创建 number */
    from(value: Int64): number
    new(value: any): Number
}

// ==================== JSON 扩展 ====================

declare const JSON: {
    /**
     * 解析 JSON 字符串为对象
     */
    parse(text: string): any
    
    /**
     * 解析 JSON 字符串为 UTSJSONObject
     */
    parseObject(text: string): UTSJSONObject | null
    
    /**
     * 解析 JSON 字符串为 UTSJSONObject 数组
     */
    parseArray(text: string): UTSJSONObject[] | null
    
    /**
     * 将对象转换为 JSON 字符串
     */
    stringify(value: any): string
}

// ==================== Array 扩展 ====================

interface Array<T> {
    /**
     * 从原生数组转换
     */
    static fromNative<T>(nativeArray: any): Array<T>
}

// ==================== Map 扩展 ====================

interface Map<K, V> {
    /**
     * 转换为 UTSJSONObject
     */
    toUTSJSONObject(): UTSJSONObject
}

// ==================== string 扩展 ====================

interface String {
    /**
     * 转换为 CharArray (Android)
     */
    toCharArray(): any
}

// ==================== 全局类型别名 ====================

/** 可为 null 的类型 */
declare type Nullable<T> = T | null

/** 可选类型 */
declare type Optional<T> = T | null | undefined

// ==================== uni-app x API ====================

/**
 * uni-app x API 成功回调
 */
interface UniSuccessResult<T = any> {
    errMsg: string
    [key: string]: any
}

/**
 * uni-app x API 失败回调
 */
interface UniFailResult {
    errMsg: string
    errCode?: number
    [key: string]: any
}

/**
 * uni-app x API 完成回调
 */
interface UniCompleteResult {
    errMsg: string
    [key: string]: any
}

/**
 * uni-app x API 通用选项
 */
interface UniBaseOptions {
    success?: (res: any) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 文件系统管理器
 */
interface FileSystemManager {
    readFile(options: {
        filePath: string
        encoding?: 'utf-8' | 'base64' | 'hex' | 'ascii' | 'binary'
        success?: (res: { data: string | ArrayBuffer }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    writeFile(options: {
        filePath: string
        data: string | ArrayBuffer
        encoding?: 'utf-8' | 'base64' | 'hex' | 'ascii' | 'binary'
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    access(options: {
        path: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    mkdir(options: {
        dirPath: string
        recursive?: boolean
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    rmdir(options: {
        dirPath: string
        recursive?: boolean
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    unlink(options: {
        filePath: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    readdir(options: {
        dirPath: string
        success?: (res: { files: string[] }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    stat(options: {
        path: string
        success?: (res: { stats: Stats }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    rename(options: {
        oldPath: string
        newPath: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    copyFile(options: {
        srcPath: string
        destPath: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
}

/**
 * 文件状态信息
 */
interface Stats {
    size: number
    lastModifiedTime: number
    isFile(): boolean
    isDirectory(): boolean
}

/**
 * 路由信息
 */
interface RouteOptions {
    url: string
    success?: (res: UniSuccessResult) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 页面信息
 */
interface PageInfo {
    route: string
    options: Record<string, string>
}

/**
 * Toast 选项
 */
interface ShowToastOptions {
    title: string
    icon?: 'success' | 'error' | 'loading' | 'none'
    image?: string
    duration?: number
    mask?: boolean
    success?: (res: UniSuccessResult) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * Loading 选项
 */
interface ShowLoadingOptions {
    title?: string
    mask?: boolean
    success?: (res: UniSuccessResult) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * Modal 选项
 */
interface ShowModalOptions {
    title?: string
    content?: string
    showCancel?: boolean
    cancelText?: string
    confirmText?: string
    cancelColor?: string
    confirmColor?: string
    success?: (res: { confirm: boolean; cancel: boolean }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * ActionSheet 选项
 */
interface ShowActionSheetOptions {
    itemList: string[]
    itemColor?: string
    success?: (res: { tapIndex: number }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * Storage 选项
 */
interface SetStorageOptions {
    key: string
    data: any
    success?: (res: UniSuccessResult) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

interface GetStorageOptions {
    key: string
    success?: (res: { data: any }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 网络请求选项
 */
interface RequestOptions {
    url: string
    method?: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'HEAD' | 'OPTIONS' | 'PATCH'
    data?: any
    header?: Record<string, string>
    timeout?: number
    dataType?: 'json' | 'text' | 'arraybuffer'
    responseType?: 'text' | 'arraybuffer'
    success?: (res: {
        statusCode: number
        data: any
        header: Record<string, string>
    }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 上传文件选项
 */
interface UploadFileOptions {
    url: string
    filePath: string
    name: string
    header?: Record<string, string>
    formData?: Record<string, any>
    success?: (res: { statusCode: number; data: string }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 下载文件选项
 */
interface DownloadFileOptions {
    url: string
    header?: Record<string, string>
    success?: (res: { statusCode: number; tempFilePath: string }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 图片选项
 */
interface ChooseImageOptions {
    count?: number
    sizeType?: ('original' | 'compressed')[]
    sourceType?: ('album' | 'camera')[]
    success?: (res: { tempFilePaths: string[]; tempFiles: { path: string; size: number }[] }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

interface PreviewImageOptions {
    urls: string[]
    current?: string | number
    success?: (res: UniSuccessResult) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 扫码选项
 */
interface ScanCodeOptions {
    onlyFromCamera?: boolean
    scanType?: ('barCode' | 'qrCode')[]
    autoDecodeCharSet?: boolean
    success?: (res: { result: string; scanType: string; charSet: string }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 位置选项
 */
interface GetLocationOptions {
    type?: 'wgs84' | 'gcj02'
    altitude?: boolean
    isHighAccuracy?: boolean
    highAccuracyExpireTime?: number
    success?: (res: {
        latitude: number
        longitude: number
        accuracy: number
        altitude: number | null
        speed: number | null
    }) => void
    fail?: (res: UniFailResult) => void
    complete?: (res: UniCompleteResult) => void
}

/**
 * 设备信息
 */
interface DeviceInfo {
    brand: string
    model: string
    system: string
    platform: string
    deviceId: string
    osName: string
    osVersion: string
    deviceBrand: string
    deviceModel: string
}

/**
 * 应用信息
 */
interface AppBaseInfo {
    appId: string
    appName: string
    appVersion: string
    appVersionCode: string
    appLanguage: string
}

/**
 * 窗口信息
 */
interface WindowInfo {
    windowWidth: number
    windowHeight: number
    statusBarHeight: number
    safeArea: {
        left: number
        right: number
        top: number
        bottom: number
        width: number
        height: number
    }
}

/**
 * uni-app x 全局对象
 */
declare const uni: {
    // ==================== 文件系统 ====================
    getFileSystemManager(): FileSystemManager
    
    // ==================== 路由 ====================
    navigateTo(options: RouteOptions): void
    navigateBack(options?: {
        delta?: number
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    redirectTo(options: RouteOptions): void
    reLaunch(options: RouteOptions): void
    switchTab(options: RouteOptions): void
    
    // ==================== 页面 ====================
    getCurrentPages(): PageInfo[]
    
    // ==================== 交互反馈 ====================
    showToast(options: ShowToastOptions): void
    hideToast(): void
    showLoading(options: ShowLoadingOptions): void
    hideLoading(): void
    showModal(options: ShowModalOptions): void
    showActionSheet(options: ShowActionSheetOptions): void
    
    // ==================== 数据缓存 ====================
    setStorage(options: SetStorageOptions): void
    setStorageSync(key: string, data: any): void
    getStorage(options: GetStorageOptions): void
    getStorageSync(key: string): any
    getStorageInfo(options: {
        success?: (res: { keys: string[]; currentSize: number; limitSize: number }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    getStorageInfoSync(): { keys: string[]; currentSize: number; limitSize: number }
    removeStorage(options: { key: string } & UniBaseOptions): void
    removeStorageSync(key: string): void
    clearStorage(): void
    clearStorageSync(): void
    
    // ==================== 网络 ====================
    request(options: RequestOptions): { abort: () => void }
    uploadFile(options: UploadFileOptions): { abort: () => void }
    downloadFile(options: DownloadFileOptions): { abort: () => void }
    
    // ==================== 图片 ====================
    chooseImage(options: ChooseImageOptions): void
    previewImage(options: PreviewImageOptions): void
    saveImageToPhotosAlbum(options: {
        filePath: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 扫码 ====================
    scanCode(options: ScanCodeOptions): void
    
    // ==================== 位置 ====================
    getLocation(options: GetLocationOptions): void
    openLocation(options: {
        latitude: number
        longitude: number
        scale?: number
        name?: string
        address?: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 设备信息 ====================
    getDeviceInfo(): DeviceInfo
    getAppBaseInfo(): AppBaseInfo
    getWindowInfo(): WindowInfo
    getSystemInfoSync(): DeviceInfo & AppBaseInfo & WindowInfo
    getSystemInfo(options: {
        success?: (res: DeviceInfo & AppBaseInfo & WindowInfo) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 剪贴板 ====================
    setClipboardData(options: {
        data: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    getClipboardData(options: {
        success?: (res: { data: string }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 震动 ====================
    vibrateShort(options?: UniBaseOptions): void
    vibrateLong(options?: UniBaseOptions): void
    
    // ==================== 网络状态 ====================
    getNetworkType(options: {
        success?: (res: { networkType: string }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 电话 ====================
    makePhoneCall(options: {
        phoneNumber: string
        success?: (res: UniSuccessResult) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 拍摄 ====================
    chooseVideo(options: {
        sourceType?: ('album' | 'camera')[]
        compressed?: boolean
        maxDuration?: number
        camera?: 'back' | 'front'
        success?: (res: { tempFilePath: string; duration: number; size: number; width: number; height: number }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    
    // ==================== 打开设置 ====================
    openSetting(options: {
        success?: (res: { authSetting: Record<string, boolean> }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
    getSetting(options: {
        success?: (res: { authSetting: Record<string, boolean> }) => void
        fail?: (res: UniFailResult) => void
        complete?: (res: UniCompleteResult) => void
    }): void
}

// ==================== getCurrentInstance ====================
declare function getCurrentInstance(): {
    proxy: {
        $page: {
            route: string
            options: Record<string, string>
        }
    } | null
}

// ==================== defineProps/defineEmits ====================
declare function defineProps<T = any>(): T
declare function defineProps<T = any>(props: T): T
declare function defineEmits<T extends string[]>(events: T): (event: T[number], ...args: any[]) => void
declare function defineEmits<T extends Record<string, any>>(events: T): T

// ==================== defineExpose ====================
declare function defineExpose(exposed: Record<string, any>): void

// ==================== withDefaults ====================
declare function withDefaults<T>(props: T, defaults: Partial<T>): T
